While declaring the table  I added  "Schemable" so it can be created a reference with in a directory, _their is no problem their_. 

```swift
import Foundation
import Bridges
 
final class Message: Table, Schemable {
    
    static var schemaName =  "chats"
    
    @Column("id")
    var id: UUID

    @Column("roomId")
    var roomId: UUID//relChatRoom
    
    @Column("type")
    var type: MessageType

    @Column("sender")
    var sender: String
    /// .....
    /// See `Table`
    init () {}
    
    init (id: UUID = UUID(),
          roomId: UUID,
          type: MessageType,
          sender: String) {
        self.id = id
        self.roomId = roomId
